  phrases: [{ nl: "Een koffie, alstublieft.", pt: "Um café, por favor.", ipa: "un kó-fi, ál-stü-blíft" }, { nl: "Mag ik een thee?", pt: "Posso tomar um chá?", ipa: "mak ik un têi" }, { nl: "Zonder suiker, graag.", pt: "Sem açúcar, por favor.", ipa: "zón-der sôi-ker, rráakh" }, { nl: "Met melk, alstublieft.", pt: "Com leite, por favor.", ipa: "met melk, ál-stü-blíft" }, { nl: "Een glas water, graag.", pt: "Um copo de água, por favor.", ipa: "un rrlás vá-ter, rráakh" }, { nl: "Kan ik hier zitten?", pt: "Posso sentar aqui?", ipa: "kan ik rir zí-tun" }],
  grammar: "“Met” significa com, e “zonder” significa sem. Essas duas palavras resolvem muitos pedidos de comida e bebida. “Een” significa um/uma, mas soa como “un” em fala rápida. Para pedir algo de forma natural, diga o item e acrescente “graag” ou “alstublieft”.",
  practice: ["Peça um café sem açúcar.", "Peça chá com leite.", "Peça um copo de água.", "Pergunte se pode sentar em uma mesa.", "Crie três pedidos usando “met” e “zonder”."]
